SELECT * FROM dev_device_reading
WHERE device_id = #{deviceId}
  AND read_at >= #{sinceTime}
ORDER BY read_at DESC

SELECT * FROM dev_device_reading
WHERE device_id = #{deviceId}
  AND read_at >= #{fromTime}
  AND read_at <= #{toTime}

      AND sensor_code = #{sensorCode}

ORDER BY read_at ASC
